// app/api/profile/route.ts
export async function PUT(req: Request) {
  const body = await req.json();
  if (!body.name) return Response.json({ error: 'name required' }, { status: 400 });
  if (body.name.length > 50) return Response.json({ error: 'name too long' }, { status: 400 });
  if (body.bio && body.bio.length > 200) return Response.json({ error: 'bio too long' }, { status: 400 });
  const session = await getServerSession();
  if (!session) return Response.json({ error: 'unauthorized' }, { status: 401 });
  const result = await prisma.user.update({ where: { id: session.user.id }, data: { name: body.name, bio: body.bio, avatarUrl: body.avatarUrl } });
  return Response.json(result);
}
